var e=JSON.parse(`[{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"동결되어 있는 동안 수없이 많은 꿈을 꿔 왔다.","JPN":"凍結されている間、いくつもの夢を見てきた。","ENG":"I had countless dreams while I was frozen asleep.","TWN":"在冰凍的歲月裡，我做過無數個夢"},"stage":{"bg":"VARUNA_01","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_13"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"새까만 그림자들이 나를 향해 손가락질하고, 원망하는 꿈.","JPN":"真っ黒な影が私を指さし、恨みを向けてくる夢。","ENG":"One was a dream of resentment where pitch-black shadows would blame me.","TWN":"夢裡有許多黑影對著我指指點點，埋怨我。"},"stage":{"bg":"VARUNA_01","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_14"},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"도망치려 해도 깊은 늪처럼 나를 끌어당기는 그림자들은, 끝내 나를 놔주지 않았다.","JPN":"逃げようとしても深い沼のように私を引き寄せる影たちは、最後まで私を放そうとはしなかった。","ENG":"No matter how much I tried to run away, they kept pulling me in closer like a deep swamp, and never let me go.","TWN":"即使試圖逃跑，那些黑影也沒有放過我，將我一點一點拉回深淵。"},"stage":{"bg":"VARUNA_01","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_15"},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"몸은 잠들어 있었지만, 정신은 늘 깨어 있었고, 눈을 뜬 뒤에야 깨달았다.","JPN":"身体は眠っていたが、意識はずっとはっきりしていて、目を覚ました後になって気づいた。","ENG":"My body was asleep, but my mind was wide awake. And I only realized it after I opened my eyes.","TWN":"身體雖然沉睡，然而意識卻很清醒。"},"stage":{"bg":"VARUNA_01","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_16"},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"나는 전우들을 잊은 죄로 지옥에 떨어졌다는 것을.","JPN":"私は戦友たちを忘れた罪で地獄に落ちたということを。","ENG":"I realized that I had fallen into hell for the sin of forgetting my comrades.","TWN":"睜開眼後，我才意識到，"},"stage":{"bg":"VARUNA_01","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_VARUNA_CA_CHAKRAM_IN_TRAILER_17"},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"전우들을 잊고, 지켜야 할 것들을 지키지 못한 죄라…….","JPN":"戦友たちを忘れ、守るべきものを守れなかった罪……","ENG":"A sin of forgetting my comrades and not being able to protect what I should've...","TWN":"我是因遺棄戰友之罪而墜入地獄的。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"어쩌면 이 현실이, 나에겐 제일 어울리는 형벌일지도 모르겠어.","JPN":"もしかしたらこの現実が、私に与えられた罰なのかもしれない。","ENG":"Maybe this reality is the punishment that suited me the best.","TWN":"或許這個現實，對我來說是最合適的懲罰。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나는 아직도…… 날 원망하는 너희들의 이름을 떠올리지 못하고 있으니까.","JPN":"私はまだ……私を恨む君たちの名前すら思い出せないんだから。","ENG":"Because I still... can't recall the names of those who blame me.","TWN":"我依然……記不起那些恨我之人的名字。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너도 그렇게 생각하고 있지 않나?","JPN":"君もそう思っているだろう？","ENG":"Don't you think so too?","TWN":"你也是這麼想的吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"네가 나타날 것이라 예상하고 있었다.","JPN":"君が現れることはわかっていた。","ENG":"I was expecting you'd show up.","TWN":"我有預料到你會出現。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"넌 과거의 나와 무슨 관계지?","JPN":"君は過去の私とはどういう関係だ？","ENG":"How do you know my past self?","TWN":"你和過去的我是什麼關係？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"벌써 거기까지 추측하신 겁니까?","JPN":"もうそこまで予想がついているのですか？","ENG":"Have you already guessed that far?","TWN":"竟然已經整理出這麼多嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"역시 아디트야군요.","JPN":"さすがアーディティヤですね。","ENG":"You must really be Aditya.","TWN":"不愧是阿迪亞。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"날 원하는 이유를 말해라. 그리고 왜 이제와서 그 뻔뻔한 면상을 들이미는지도.","JPN":"私に何を求めている。今更その厚かましい面を、再び現した理由はなんだ。","ENG":"Tell me why you want me, and why you are now brazenly showing your face.","TWN":"告訴我你找我的理由，還有為什麼現在才厚著臉皮出現。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신 혼자서는 아무것도 할 수 없다는 것을 상기시켜주고 싶었습니다.","JPN":"あなた一人では何もできないということを、思い出させてあげたかった。","ENG":"I wanted to remind you that you can't do anything alone.","TWN":"我只是想提醒你，你一個人是很有限的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그리고 역시나…… 우리가 아니면 당신은 혼자일 수밖에 없군요.","JPN":"それにやっぱり……我々がいなければ、あなたは一人になるしかない。","ENG":"And, as expected... that you will be alone without us.","TWN":"而且……如果沒有我們，你就只能能是一個人。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나에게 살려달라 울부짖던 동료들, 그리고 아샤, 그리고 침식체.","JPN":"私に助けてくれと泣き叫んだ仲間たち、アーシャ、侵食体。","ENG":"The cries of my comrades, begging me to save them. Asha, and the C.O.","TWN":"向我哭喊求救的戰友，還有阿莎，還有侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그것이 너와 관련이 없다고 생각하기가 어렵군.","JPN":"それらが君と無関係とは思えない。","ENG":"It's hard to believe that they have nothing to do with me.","TWN":"很難認為這一切與我無關。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그러니 다시 묻겠다. 날 원하는 이유를 말해라.","JPN":"だから、もう一度聞く。私に何を求める。","ENG":"So, I will ask again. Why do you want me?","TWN":"那麼，我再問你一次。你找我是要做什麼。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"카운터가 된 후 사막을 떠돌던 저에게, 당신은 라비라는 새 이름을 지어주셨죠.","JPN":"カウンターになり、砂漠を彷徨っていた私に、あなたはラビという新しい名前を授けてくださいました。","ENG":"You gave me a new name, Ravi, when I was wandering the desert after becoming a Counter.","TWN":"在我成為制裁者，徘徊於沙漠之時，拉維，這個名字是你替我取的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신의 믿음직한 동료이자, 당신의 불꽃입니다.","JPN":"あなたにとって信頼のおける仲間であり、あなたの炎です。","ENG":"I was your trusty comrade and your flame.","TWN":"我是你值得信賴的夥伴，也是你的火焰。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"앞으로도 당신의 곁에서, 영원히 당신과 함께하기 위해 우리를 대표해 모습을 드러낸겁니다.","JPN":"これからもあなたのそばで、永遠にあなたと行動をともにするために、我々を代表する者として、私が来たのです。","ENG":"I have appeared in front of you on behalf of everyone who wishes to be by your side forever.","TWN":"今後也會在你身邊，永遠與你在一起，我代表大家出現在這裡。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"다른 동료들도 기다리고 있거든요. 당신을.","JPN":"他の仲間たちも待っているのです、あなたを。","ENG":"Everyone else is waiting for you.","TWN":"其他同伴也在一直等著你。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Kgh...","TWN":"咳……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"정화 목표는 타입 미상의 거대 침식체.","JPN":"浄化のターゲットはタイプ不明の巨大侵食体だ。","ENG":"The purification target is a colossal C.O. of an unknown type.","TWN":"淨化目標為類型不明的巨型侵蝕體。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"현실에 나타나 영향을 끼치는 이상, 우리는 놈을 정화해야 한다.","JPN":"現実に現れ、影響を及ぼしている以上、我々は奴を浄化しなければならない。","ENG":"Since it has appeared in the Normalside and affected it, we must purify it.","TWN":"既然它出現在現世中並已經產生異常，就必須受到淨化。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"우리가 싸우기 적합한 상황이 아니란 것을 안다. 하지만 우리는 그럼에도, 나아가야 해.","JPN":"この戦いは我々に圧倒的不利であることは承知している。しかし、それでも我々は進まなければならん。","ENG":"I'm aware we are not in a suitable position to fight. Yet, we must go forth.","TWN":"我知道這種情況不適合我們戰鬥。但即便如此，我們也必須前進。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"모두들, 미안하다.","JPN":"皆、すまない。","ENG":"I'm sorry, everyone.","TWN":"各位，我很對不起。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"특히 너에게 미안하군. 라비. 딸과 둘이서 여행을 다니고 있지 않았나?","JPN":"特に君には申し訳ないと思っている。ラビ。娘と二人で旅をしているのだろう？","ENG":"Especially to you, Ravi. Didn't you say you wanted to go traveling with your daughter?","TWN":"特別是你，拉維。你還在和女兒一起旅行……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"라비…… 아샤의 아버지…….","JPN":"ラビ……アーシャの父親。","ENG":"Ravi... Asha's father...","TWN":"拉維……阿莎的爸爸……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그것은 당신의, 그리고 <color=#ffd34c>우리</color>의 기억 중 일부입니다.","JPN":"それはあなたの、そして<color=#ffd34c>我々</color>の記憶の一部です。","ENG":"This is a portion of yours and <color=#ffd34c>our</color> memory.","TWN":"那是你，和<color=#ffd34c>我們</color>記憶裡的一部分。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"기억이 전달될 수 있다는 것은 당신과 우리가 여전히 함께할 수 있다는 거죠.","JPN":"記憶を共有できるということは、あなたと我々はまだ、一緒になれるということを意味するのでしょう。","ENG":"The fact that these memories can still be passed to you means that you can still be with us.","TWN":"這份記憶能夠傳遞給你，就表示你和我們仍然可以在一起。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리와 함께 해주십시오.","JPN":"我々と一緒になりましょう。","ENG":"Please, join us.","TWN":"請和我們一起吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"다시 한번 우리의 태양이 되어 세상의 어둠을 몰아내 주십시오.","JPN":"もう一度、我々の太陽となり、世界から闇を追い払ってください。","ENG":"Become our sun once again and rid the world of this darkness.","TWN":"請再次成為我們的太陽，驅散世界的黑暗。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……그건 내가 원하는 대답이 아니다.","JPN":"……それは、私が求めている答えではない。","ENG":"...That is not what I asked.","TWN":"……那不是我想要的答案。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리는 눈앞의 어둠을 정화하는 자들입니다.","JPN":"我々の使命は、目の前の闇を浄化することです。","ENG":"We are those who purify the darkness before our eyes.","TWN":"我們是淨化眼前黑暗的人。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그리고 당신은 그런 저희들을 인도하는 태양이죠.\xA0","JPN":"そして、あなたはそんな我々を導く太陽だ。\xA0","ENG":"And you are the sun that guides us.\xA0","TWN":"而你就是引導我們的太陽。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저는 당신에게 첫번째로 이름을 받은 자.","JPN":"私はあなたから初めて名前を授けられた者。","ENG":"I am the first to receive a name from you.","TWN":"我是第一個從你那裡得到名字的人。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"삿된 것을 정화하는 불꽃, 라비입니다. 이젠 기억하셨으면 좋겠습니다만.","JPN":"邪なものを浄化する炎、ラビです。そろそろ覚えていただきたいですね。","ENG":"My name is Ravi, the flame that purifies evil. I can only hope that you remember me now.","TWN":"淨化邪惡的烈火，拉維。希望你現在能記住它。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너는 라비가 아니야.","JPN":"君はラビではない。","ENG":"You are not Ravi.","TWN":"不，你不是拉維。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"눈앞의 어둠을 정화한다.","JPN":"目の前の闇を浄化する。","ENG":"We purify the darkness before our eyes.","TWN":"淨化眼前的黑暗。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"우리는 숭고한 임무를 갖고 앞으로 갈 뿐이야. 후회할 리 없지.","JPN":"我々は崇高な任務を遂行するために進み続ける。後悔なんかあるわけがない。","ENG":"And go forth with our noble mission. There is no regret here.","TWN":"我們肩負著崇高的使命前進，絕不會感到後悔。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그러니 미안해할 필요 없다.","JPN":"だから申し訳ないなどと思わなくていい。","ENG":"So, you don't need to apologize to me.","TWN":"所以不用道歉。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"나는 아샤의 내일을 위해 이 한 몸 불사를 뿐이니까.","JPN":"俺はアーシャの明日のために、この身を捧げるだけだ。","ENG":"I am merely risking my life so Asha's future can be bright.","TWN":"我是為了阿莎的明天而燃燒自己的。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너같이 미지근하고, 속내가 복잡한 녀석은 불꽃의 이름을 받을 자격이 없다.","JPN":"君のような生ぬるく、いけ好かない下心を持っているやつに炎の名を受け継ぐ資格などない。","ENG":"Someone who is as lukewarm and complicated as you does not deserve the name of the flame.","TWN":"像你這樣優柔寡斷、心思複雜的傢伙，不配擁有火焰之名。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"넌 아합이다. 너에게 딱 어울리는 이름이지.","JPN":"君はアハブだ。それが君に相応しい名前だ。","ENG":"You are Ahab. That's a name that befits you.","TWN":"你是亞哈，這個名字非常適合你。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너는 그자처럼 불꽃을 피우지 못해. 나는 그 이름을 허락하지 않는다.","JPN":"君は彼のような炎を起こすことはできない。私はその名前を許可しない。","ENG":"You cannot ignite a flame like him, and I have never allowed that name to you.","TWN":"你無法像他那樣燃起火焰，我不允許你使用那個名字。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그렇군요. 기억을 잃어버리면서 저에 대한 것을 모두 잊은 모양입니다.","JPN":"そうですか。記憶をなくす時、私についてもすべて忘れてしまったようですね。","ENG":"I see. It seems that you have forgotten about us when losing your memories.","TWN":"原來如此。看來你失去記憶的同時，也把關於我的一切都遺忘了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저는 라비입니다.","JPN":"私はラビです。","ENG":"I am Ravi.","TWN":"我是拉維。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"언제나 최선봉에 서서, 당신이 명령한 모든 어둠을 불사르는.","JPN":"常に先鋒に立ち、あなたの命令に従ってあらゆる闇を焼き払う。","ENG":"I have always been at the forefront, burning away all the darkness through your command.","TWN":"永遠站在最前線，遵從你的命令，燃燒所有黑暗……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"첫 번째 불꽃!!!","JPN":"最初の炎！！！","ENG":"The first flame!!","TWN":"……的第一道火焰！！！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_28"},{"id":"L45_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"허락하지 않으셔도 괜찮습니다.\xA0","JPN":"許可など必要ありません。\xA0","ENG":"It is all right if you don't allow it.\xA0","TWN":"你不承認也沒有關係。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신을 강제로 굴복시켜서라도, 우리와 함께하도록 만들면 되니까!!!","JPN":"あなたを力ずくで屈服させ、我々と一緒になるようにすればいいのだから！！","ENG":"Because I will make you join us, even if it means using force!!","TWN":"即使要強迫你屈服，也要讓你和我們在一起！！！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};